#!/usr/bin/env node
/**
 * Generates typed config artifacts for each SDK from packages/sdk/config.json.
 * This keeps one source of truth while avoiding runtime cross-package file reads.
 *
 * Generated files:
 * - packages/sdk-typescript/src/config.generated.ts
 * - packages/sdk-python/whyops/_config_gen.py
 * - packages/sdk-go/config_gen.go
 *
 * Run: npm run sync:sdk-config
 */
import { readFileSync, writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const masterPath = join(root, 'packages/sdk/config.json');

let cfg;
try {
  cfg = JSON.parse(readFileSync(masterPath, 'utf8'));
} catch (e) {
  console.error('packages/sdk/config.json is invalid or missing:', e.message);
  process.exit(1);
}

const eventTypesTs = cfg.eventTypes.map((et) => `  '${et}',`).join('\n');
const eventTypesPy = cfg.eventTypes.map((et) => `    "${et}",`).join('\n');
const requiredMetadataEntriesTs = Object.entries(cfg.requiredMetadata)
  .map(([eventType, fields]) => `  '${eventType}': ${JSON.stringify(fields)} as const,`)
  .join('\n');

const requiredMetadataEntriesPy = Object.entries(cfg.requiredMetadata)
  .map(([eventType, fields]) => `    "${eventType}": ${JSON.stringify(fields)},`)
  .join('\n');

const tsFile = `// Code generated by scripts/sync-sdk-config.mjs — DO NOT EDIT.
// Source of truth: packages/sdk/config.json
// Regenerate: npm run sync:sdk-config (from monorepo root)

export const SDK_VERSION = "${cfg.version}" as const;

export const DEFAULT_PROXY_URL = "${cfg.defaults.proxyUrl}" as const;
export const DEFAULT_ANALYSE_URL = "${cfg.defaults.analyseUrl}" as const;

export const HTTP_TIMEOUT_MS = ${cfg.http.timeoutMs} as const;
export const RETRY_DELAYS_MS = ${JSON.stringify(cfg.http.retry.delaysMs)} as const;
export const RETRYABLE_STATUS_CODES = ${JSON.stringify(cfg.http.retry.retryableStatusCodes)} as const;

export const ENDPOINTS = {
  agentInitPrimary: "${cfg.endpoints.agentInitPrimary}",
  agentInitFallback: "${cfg.endpoints.agentInitFallback}",
  eventsIngest: "${cfg.endpoints.eventsIngest}",
} as const;

export const HEADERS = {
  agentName: "${cfg.headers.agentName}",
  apiKeyAnthropic: "${cfg.headers.apiKeyAnthropic}",
  contentTypeName: "${cfg.headers.contentTypeName}",
  contentTypeValue: "${cfg.headers.contentTypeValue}",
} as const;

export const LOG_PREFIX = "${cfg.logging.prefix}" as const;

export const EVENT_TYPES = [
${eventTypesTs}
] as const;

export const REQUIRED_METADATA_BY_EVENT = {
${requiredMetadataEntriesTs}
} as const;
`;

const tsOutPath = join(root, 'packages/sdk-typescript/src/config.generated.ts');
writeFileSync(tsOutPath, tsFile, 'utf8');
console.log('✓  generated → packages/sdk-typescript/src/config.generated.ts');

const pyFile = `# Code generated by scripts/sync-sdk-config.mjs — DO NOT EDIT.
# Source of truth: packages/sdk/config.json
# Regenerate: npm run sync:sdk-config (from monorepo root)

from typing import Literal

SDK_VERSION = "${cfg.version}"

DEFAULT_PROXY_URL = "${cfg.defaults.proxyUrl}"
DEFAULT_ANALYSE_URL = "${cfg.defaults.analyseUrl}"

HTTP_TIMEOUT_S = ${cfg.http.timeoutMs / 1000}
RETRY_DELAYS_S = ${JSON.stringify(cfg.http.retry.delaysMs.map((ms) => ms / 1000))}
RETRYABLE_STATUS_CODES = frozenset(${JSON.stringify(cfg.http.retry.retryableStatusCodes)})

ENDPOINT_AGENT_INIT_PRIMARY = "${cfg.endpoints.agentInitPrimary}"
ENDPOINT_AGENT_INIT_FALLBACK = "${cfg.endpoints.agentInitFallback}"
ENDPOINT_EVENTS_INGEST = "${cfg.endpoints.eventsIngest}"

HEADER_AGENT_NAME = "${cfg.headers.agentName}"
HEADER_ANTHROPIC_KEY = "${cfg.headers.apiKeyAnthropic}"
HEADER_CONTENT_TYPE_NAME = "${cfg.headers.contentTypeName}"
HEADER_CONTENT_TYPE_VALUE = "${cfg.headers.contentTypeValue}"

LOG_PREFIX = "${cfg.logging.prefix}"

EventType = Literal[
${eventTypesPy}
]

EVENT_TYPES: tuple[EventType, ...] = (
${eventTypesPy}
)

REQUIRED_METADATA_BY_EVENT: dict[str, list[str]] = {
${requiredMetadataEntriesPy}
}
`;

const pyOutPath = join(root, 'packages/sdk-python/whyops/_config_gen.py');
writeFileSync(pyOutPath, pyFile, 'utf8');
console.log('✓  generated → packages/sdk-python/whyops/_config_gen.py');

const retryDelaysDuration = cfg.http.retry.delaysMs
  .map((ms) => `${ms} * time.Millisecond`)
  .join(', ');

const retryableStatusEntries = cfg.http.retry.retryableStatusCodes
  .map((c) => `\t${c}: true,`)
  .join('\n');

const GO_ACRONYMS = new Set(['llm', 'sdk', 'url', 'api', 'id', 'http']);

function toGoIdent(snakeCase) {
  return snakeCase
    .split('_')
    .map((w) => GO_ACRONYMS.has(w) ? w.toUpperCase() : w[0].toUpperCase() + w.slice(1))
    .join('');
}

const eventTypeConsts = cfg.eventTypes
  .map((et) => `\tEventType${toGoIdent(et)} EventType = "${et}"`)
  .join('\n');

const goFile = `// Code generated by scripts/sync-sdk-config.mjs — DO NOT EDIT.
// Source of truth: packages/sdk/config.json
// Regenerate: npm run sync:sdk-config (from monorepo root)
package whyops

import "time"

const SDKVersion = "${cfg.version}"

// Default service URLs — used when proxyBaseURL / analyseBaseURL are not set in Config.
const (
\tDefaultProxyURL   = "${cfg.defaults.proxyUrl}"
\tDefaultAnalyseURL = "${cfg.defaults.analyseUrl}"
)

// HTTP settings
const HTTPTimeoutMs = ${cfg.http.timeoutMs}

// API endpoint paths appended to base URLs.
const (
\tEndpointAgentInitPrimary  = "${cfg.endpoints.agentInitPrimary}"
\tEndpointAgentInitFallback = "${cfg.endpoints.agentInitFallback}"
\tEndpointEventsIngest      = "${cfg.endpoints.eventsIngest}"
)

// HTTP header names.
const (
\tHeaderAgentName      = "${cfg.headers.agentName}"
\tHeaderAnthropicKey   = "${cfg.headers.apiKeyAnthropic}"
\tHeaderContentType    = "${cfg.headers.contentTypeName}"
\tHeaderContentJSON    = "${cfg.headers.contentTypeValue}"
\tLogPrefix            = "${cfg.logging.prefix}"
)

var retryDelays = []time.Duration{${retryDelaysDuration}}
var retryableStatuses = map[int]bool{
${retryableStatusEntries}
}

// EventType string enum — all supported values.
const (
${eventTypeConsts}
)
`;

const goOutPath = join(root, 'packages/sdk-go/config_gen.go');
writeFileSync(goOutPath, goFile, 'utf8');
console.log('✓  generated → packages/sdk-go/config_gen.go');
console.log('Done.');
